```rust
pub struct TypeRegistry {
    /// OID -> Type info
    types: HashMap<u32, TypeInfo>,
    /// Name -> OID for lookups
    names: HashMap<String, u32>,
}

pub struct TypeInfo {
    pub oid: u32,
    pub name: String,
    pub array_oid: Option<u32>,
    pub element_oid: Option<u32>,  // For arrays
    pub category: TypeCategory,
}

pub enum TypeCategory {
    Boolean,
    Numeric,
    String,
    DateTime,
    Binary,
    Json,
    Uuid,
    Array,
    Composite,
    Unknown,
}

impl TypeRegistry {
    pub fn new() -> Self {
        let mut registry = Self {
            types: HashMap::new(),
            names: HashMap::new(),
        };

        // Register built-in types
        registry.register(TypeInfo {
            oid: oid::BOOL,
            name: "bool".to_string(),
            array_oid: Some(oid::BOOL_ARRAY),
            element_oid: None,
            category: TypeCategory::Boolean,
        });
        // ... register all built-in types

        registry
    }

    pub fn get(&self, oid: u32) -> Option<&TypeInfo> {
        self.types.get(&oid)
    }

    pub fn by_name(&self, name: &str) -> Option<&TypeInfo> {
        self.names.get(name).and_then(|oid| self.types.get(oid))
    }
}
