### Binary Format

```rust
pub trait BinaryEncode {
    fn encode_binary(&self, buf: &mut Vec<u8>);
}

pub trait BinaryDecode: Sized {
    fn decode_binary(data: &[u8]) -> Result<Self, Error>;
}

// Integer types: big-endian encoding
impl BinaryEncode for i16 {
    fn encode_binary(&self, buf: &mut Vec<u8>) {
        buf.extend_from_slice(&self.to_be_bytes());
    }
}

impl BinaryDecode for i16 {
    fn decode_binary(data: &[u8]) -> Result<Self, Error> {
        if data.len() != 2 {
            return Err(Error::Type(TypeError::binary_length(2, data.len())));
        }
        Ok(i16::from_be_bytes([data[0], data[1]]))
    }
}

impl BinaryEncode for i32 {
    fn encode_binary(&self, buf: &mut Vec<u8>) {
        buf.extend_from_slice(&self.to_be_bytes());
    }
}

impl BinaryDecode for i32 {
    fn decode_binary(data: &[u8]) -> Result<Self, Error> {
        if data.len() != 4 {
            return Err(Error::Type(TypeError::binary_length(4, data.len())));
        }
        Ok(i32::from_be_bytes([data[0], data[1], data[2], data[3]]))
    }
}

// Bool: single byte
impl BinaryEncode for bool {
    fn encode_binary(&self, buf: &mut Vec<u8>) {
        buf.push(if *self { 1 } else { 0 });
    }
}

impl BinaryDecode for bool {
    fn decode_binary(data: &[u8]) -> Result<Self, Error> {
        if data.len() != 1 {
            return Err(Error::Type(TypeError::binary_length(1, data.len())));
        }
        Ok(data[0] != 0)
    }
}

// UUID: 16 bytes
impl BinaryEncode for Uuid {
    fn encode_binary(&self, buf: &mut Vec<u8>) {
        buf.extend_from_slice(self.as_bytes());
    }
}

impl BinaryDecode for Uuid {
    fn decode_binary(data: &[u8]) -> Result<Self, Error> {
        if data.len() != 16 {
            return Err(Error::Type(TypeError::binary_length(16, data.len())));
        }
        Ok(Uuid::from_bytes([
            data[0], data[1], data[2], data[3],
            data[4], data[5], data[6], data[7],
            data[8], data[9], data[10], data[11],
            data[12], data[13], data[14], data[15],
        ]))
    }
}

// Timestamp: microseconds since 2000-01-01
impl BinaryEncode for NaiveDateTime {
    fn encode_binary(&self, buf: &mut Vec<u8>) {
        let epoch = NaiveDateTime::parse_from_str("2000-01-01 00:00:00", "%Y-%m-%d %H:%M:%S").unwrap();
        let micros = (*self - epoch).num_microseconds().unwrap_or(0);
        buf.extend_from_slice(&micros.to_be_bytes());
    }
}

impl BinaryDecode for NaiveDateTime {
    fn decode_binary(data: &[u8]) -> Result<Self, Error> {
        let micros = i64::decode_binary(data)?;
        let epoch = NaiveDateTime::parse_from_str("2000-01-01 00:00:00", "%Y-%m-%d %H:%M:%S").unwrap();
        Ok(epoch + chrono::Duration::microseconds(micros))
    }
}
